fn local_agent_command(
    spec: &TaskSpec,
    output_dir: &Path,
    no_collect: bool,
    position_pct: Option<&str>,
) -> String {
    let mut parts = vec![
        "cargo".to_string(),
        "run".to_string(),
        "--release".to_string(),
        "--".to_string(),
        "agent-run".to_string(),
        "--workflow".to_string(),
        spec.workflow.to_string(),
        "--save".to_string(),
        "--out-dir".to_string(),
        relative(output_dir),
    ];
    if no_collect {
        parts.push("--no-collect".to_string());
    }
    if spec.workflow == "valuation-decision"
        && let Some(position_pct) = position_pct
    {
        parts.extend([
            "--current-position-pct".to_string(),
            position_pct.to_string(),
        ]);
    }
    shell_join(&parts)
